    }

    long rows = n, cols = m;
    long minSensors = 0;

    // Iterate over each row
    for (long i = 0; i < rows; i += 2 * k) {
        // Iterate over each column
        for (long j = 0; j < cols; j += 2 * k) {
            // Place a sensor at (i, j)
            minSensors++;

            // Check if the sensor covers the entire grid
            if (i + k >= rows - 1 && j + k >= cols - 1) {
                return minSensors;
            }
        }
    }

    return minSensors;
}
