public static long solve(long n, long m, long k) {
    if (k == 0) {
        return n * m;
    }

    long rows = n;
    long cols = m;
    long result = 0;

    for (long i = 0; i < rows; i += 2 * k) {
        for (long j = 0; j < cols; j += 2 * k) {
            result++;
        }
    }

